challenges.solution:
export class MissionStore {
  missions = [];
  nextId = 1;

  getAll() { return [...this.missions]; }
  getActive() { return this.missions.filter(m => m.status === 'active'); }

  create(name) {
    const m = { id: this.nextId++, name, status: 'pending' };
    this.missions.push(m);
    return m;
  }

  launch(id) {
    const m = this.missions.find(m => m.id === id);
    if (!m) return false;
    m.status = 'active';
    return true;
  }

  complete(id) {
    const m = this.missions.find(m => m.id === id);
    if (!m) return false;
    m.status = 'complete';
    return true;
  }
}

export class MissionDashboard {
  results = [];
  store;

  constructor(store) {
    this.store = store;
  }

  get stats() {
    const all = this.store.getAll();
    return {
      total: all.length,
      active: all.filter(m => m.status === 'active').length,
      complete: all.filter(m => m.status === 'complete').length,
    };
  }

  search(term) {
    const t = term.toLowerCase();
    this.results = this.store.getAll().filter(m => m.name.toLowerCase().includes(t));
  }
}

export class MissionPipeline {
  store;

  constructor(store) {
    this.store = store;
  }

  async run(names) {
    for (const name of names) {
      const m = this.store.create(name);
      if (name.toLowerCase().includes('alpha')) {
        this.store.launch(m.id);
      }
    }
    return this.store.getAll();
  }
}
